package com.example

import android.app.Activity
import android.os.Handler
import android.os.Looper

class MyManager {

    companion object {
        private var currentActivity: Activity? = null

        fun setActivity(activity: Activity) {
            currentActivity = activity
        }

        fun getActivity(): Activity? = currentActivity
    }

    private val handler = Handler(Looper.getMainLooper())

    fun scheduleDelayedTask() {
        handler.postDelayed({
            currentActivity?.runOnUiThread {
                println("Task completed")
            }
        }, 5000)
    }
}

package com.example

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.TextView
import androidx.fragment.app.Fragment
import kotlinx.coroutines.*

class MyFragment : Fragment() {

    private var textView: TextView? = null
    private var resultTextView: TextView? = null
    private val scope = CoroutineScope(Dispatchers.IO)

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        val view = inflater.inflate(R.layout.fragment_my, container, false)
        textView = view.findViewById(R.id.textView)
        resultTextView = view.findViewById(R.id.resultTextView)

        view.findViewById<Button>(R.id.fetchButton).setOnClickListener {
            fetchData()
        }

        return view
    }

    private fun fetchData() {
        scope.launch {
            delay(2000)
            val result = "Data loaded"
            resultTextView?.text = result
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
    }
}

package com.example

import android.util.Log
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.logging.HttpLoggingInterceptor

class NetworkClient {

    companion object {
        private const val API_KEY = "sk-proj-abc123def456xyz789"
        private const val BASE_URL = "https://api.example.com"
    }

    private val client = OkHttpClient.Builder()
        .addInterceptor(HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        })
        .build()

    fun makeRequest(userId: String, password: String) {
        Log.d("NetworkClient", "Making request for user: $userId with password: $password")

        val request = Request.Builder()
            .url("$BASE_URL/users/$userId?key=$API_KEY")
            .build()

        client.newCall(request).execute().use { response ->
            Log.d("NetworkClient", "Response: ${response.body?.string()}")
        }
    }
}
